1	------------------------------------------------------------------------------
2	--  Copyright (c) 2018 by Paul Scherrer Institute, Switzerland
3	--  All rights reserved.
4	--  Authors: Oliver Bruendler
5	------------------------------------------------------------------------------
6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- unwrap phase signal for instance +/- 180 -> 360° and so on with indicator
11	------------------------------------------------------------------------------
12	library ieee;
13	use ieee.std_logic_1164.all;
14	use ieee.numeric_std.all;
15	use ieee.math_real.all;
16	
17	use work.psi_common_array_pkg.all;
18	use work.psi_common_math_pkg.all;
19	use work.psi_fix_pkg.all;
20	use work.psi_common_logic_pkg.all;
21	
22	-- $$ tbpkg=psi_lib.psi_tb_textfile_pkg,psi_lib.psi_tb_txt_util $$
23	-- $$ processes=stimuli,response $$
24	entity psi_fix_phase_unwrap is
25	  generic(
26	    in_fmt_g   : psi_fix_fmt_t := (1, 0, 15);                           -- input format
27	    out_fmt_g  : psi_fix_fmt_t := (0, 1, 15);                           -- output format
28	    round_g    : psi_fix_rnd_t := psi_fix_trunc;                        -- round or trunc
29	    rst_pol_g  : std_logic   := '1'                                     -- reset polarity
30	  );
31	  port(
32	    clk_i  : in  std_logic;                                             -- $$ type=Clk; freq=127e6 $$
33	    rst_i  : in  std_logic;                                             -- $$ type=Rst; Clk=Clk $$
34	    dat_i  : in  std_logic_vector(psi_fix_size(in_fmt_g) - 1 downto 0); -- data input
35	    vld_i  : in  std_logic;                                             -- valid signal input
36	    dat_o  : out std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);-- data output
37	    vld_o  : out std_logic;                                             -- valid signal output
38	    wrap_o : out std_logic                                              -- wrap output
39	  );
40	end entity;
41	
42	architecture rtl of psi_fix_phase_unwrap is
43	
44	  -- Constants
45	  constant SumFmt_c  : psi_fix_fmt_t := (1, max(out_fmt_g.I + 1, 1), in_fmt_g.F);
46	  constant DiffFmt_c : psi_fix_fmt_t := (1, 0, in_fmt_g.F);
47	
48	  -- Two Process Method
49	  type two_process_r is record
50	    Vld       : std_logic_vector(0 to 3);
51	    InData_0  : std_logic_vector(dat_i'range);
52	    InData_1  : std_logic_vector(dat_i'range);
53	    InLast_0  : std_logic_vector(dat_i'range);
54	    Diff_1    : std_logic_vector(psi_fix_size(DiffFmt_c) - 1 downto 0);
55	    Sum_2     : std_logic_vector(psi_fix_size(SumFmt_c) - 1 downto 0);
56	    Wrap_2    : std_logic;
57	    OutData_3 : std_logic_vector(psi_fix_size(out_fmt_g) - 1 downto 0);
58	    OutWrap_3 : std_logic;
59	  end record;
60	  signal r, r_next : two_process_r;
61	
62	begin
63	  --------------------------------------------------------------------------
64	  -- Assertions
65	  --------------------------------------------------------------------------
66	  assert out_fmt_g.S = 1 report "###ERROR###: psi_fix_phase_unwrap: output format must be signed!" severity error;
67	  assert out_fmt_g.I >= 1 report "###ERROR###: psi_fix_phase_unwrap: output format must at least have one integer bit!" severity error;
68	
69	  --------------------------------------------------------------------------
70	  -- Combinatorial Process
71	  --------------------------------------------------------------------------
72	  proc_comb : process(r, vld_i, dat_i)
73	    variable Sum_v  : std_logic_vector(psi_fix_size(SumFmt_c) - 1 downto 0);
74	    variable Wrap_v : std_logic;
75	    variable v      : two_process_r;
76	  begin
77	    -- hold variables stable
78	    v := r;
79	
80	    -- *** Pipe Handling ***
81	    v.Vld(v.Vld'low + 1 to v.Vld'high) := r.Vld(r.Vld'low to r.Vld'high - 1);
82	
83	    -- *** Stage 0 (Input Stage) ***
84	    v.Vld(0)   := vld_i;
85	    v.InData_0 := dat_i;
86	    -- Delay input data by one sample
87	    if r.Vld(0) = '1' then
88	      v.InLast_0 := r.InData_0;
89	    end if;
90	
91	    -- *** Stage 1 (Differentiate) ***
92	    if r.Vld(0) = '1' then
93	      v.Diff_1   := psi_fix_sub(r.InData_0, in_fmt_g, r.InLast_0, in_fmt_g, DiffFmt_c, psi_fix_trunc, psi_fix_wrap);
94	      v.InData_1 := r.InData_0;
95	    end if;
96	
97	    -- *** Stage 2 (Summation) ***
98	    Sum_v  := psi_fix_add(r.Sum_2, SumFmt_c, r.Diff_1, DiffFmt_c, SumFmt_c);
99	    Wrap_v := '0';
100	    if not psi_fix_in_range(Sum_v, SumFmt_c, out_fmt_g, round_g) then
101	      Sum_v  := psi_fix_resize(r.InData_1, in_fmt_g, SumFmt_c);
102	      Wrap_v := '1';
103	    end if;
104	    if r.Vld(1) = '1' then
105	      v.Sum_2  := Sum_v;
106	      v.Wrap_2 := Wrap_v;
107	    end if;
108	
109	    -- *** Stage 3 (Output Rounding) ***
110	    if r.Vld(2) = '1' then
111	      v.OutData_3 := psi_fix_resize(r.Sum_2, SumFmt_c, out_fmt_g, round_g);
112	      v.OutWrap_3 := r.Wrap_2;
113	    end if;
114	
115	    -- Apply to record
116	    r_next <= v;
117	
118	  end process;
119	
120	  --------------------------------------------------------------------------
121	  -- Output Assignment
122	  --------------------------------------------------------------------------
123	  vld_o  <= r.Vld(3);
124	  dat_o  <= r.OutData_3;
125	  wrap_o <= r.OutWrap_3;
126	
